    col_clear, col_spacer, col_launch = st.columns([1, 0.15, 2])
    with col_clear:
        if st.button("🗑️ Clear Code", key="clear_code_btn", use_container_width=True):
            st.session_state["code_input"] = ""
            st.session_state["code_instructions"] = ""
            if "lab_response" in st.session_state:
                del st.session_state["lab_response"]
            st.rerun()

    with col_launch:
        if st.button("🚀 Launch Analysis", key="launch_analysis_btn", use_container_width=True):
            current_code = st.session_state.get("code_input", "")
            if not current_code.strip() and code_action != "Write From Scratch":
                st.warning("⚠️ No code detected — paste your code above before launching.")
            else:
                current_instructions = st.session_state.get("code_instructions", "")
                lang_lower = code_lang.lower() if code_lang != "Other" else ""

                prompt_parts = [
                    f"You are a world-class software engineer. The user wants you to: **{code_action}**",
                    f"Programming language: {code_lang}",
                ]

                if current_code.strip():
                    prompt_parts.append(f"Code:\n```{lang_lower}\n{current_code}\n```")
                if current_instructions.strip():
                    prompt_parts.append(f"Additional instructions: {current_instructions}")

                lab_prompt = "\n\n".join(prompt_parts)

                with st.spinner("🔬 Scanning code..."):
                    try:
                        lab_response = chat(lab_prompt)
                        st.session_state["lab_response"] = lab_response
                        st.session_state["lab_lang"] = code_lang
                    except Exception as e:
                        logger.error(f"Code analysis error: {e}")
                        st.error("❌ Error analyzing code. Please try again.")

    # Display lab results
    if "lab_response" in st.session_state:
        lab_resp = st.session_state["lab_response"]
        lab_lang_saved = st.session_state.get("lab_lang", "Python")

        ext_map = get_file_extension_map()
        file_ext = ext_map.get(lab_lang_saved, "txt")
        escaped_resp = html_lib.escape(lab_resp)

        st.markdown(f"""
        <div class="lab-findings-wrapper">
            <div class="lab-findings-label">⚡ Ruby's Findings</div>
            <pre style="
                color: #e0c8ff;
                font-family: 'Courier New', monospace;
                font-size: 0.82rem;
                line-height: 1.6;
                white-space: pre-wrap;
                word-break: break-word;
                margin: 0 0 1rem 0;
            ">{escaped_resp}</pre>
        </div>
        """, unsafe_allow_html=True)

        col_copy, col_download = st.columns(2)
        with col_copy:
            if st.button("📋 Copy Response", key="copy_response"):
                st.write("Response copied to clipboard!")

        with col_download:
            st.download_button(
                label=f"💾 Save (.{file_ext})",
                data=lab_resp,
                file_name=f"ruby_findings.{file_ext}",
                mime="text/plain",
                key="lab_download"
            )

    st.divider()

    # Chat interface
    for message in st.session_state.messages:
        with st.chat_message(message["role"]):
            st.markdown(message["content"])

    if prompt := st.chat_input("Send transmission to Ruby..."):
        with st.chat_message("user"):
            st.markdown(prompt)

        st.session_state.messages.append({
            "role": "user",
            "content": prompt
        })

        # Prepare prompt with document context
        if document_text:
            truncated_text = document_text[:MAX_DOCUMENT_CHARS]
            full_prompt = f"The user has uploaded a document. Here is its content:\n\n{truncated_text}\n\nUser question: {prompt}"
        else:
            full_prompt = prompt

        with st.chat_message("assistant"):
            with st.spinner("Ruby is scanning the cosmos..."):
                try:
                    response = chat(
                        full_prompt,
                        image_data=uploaded_image_data,
                        image_media_type=uploaded_image_media_type
                    )
                    st.markdown(response)

                    st.session_state.messages.append({
                        "role": "assistant",
                        "content": response
                    })
                except Exception as e:
                    logger.error(f"Chat error: {e}")
                    st.error("❌ Error communicating with Ruby. Please try again.")

    # Export chat functionality
    if st.session_state.get("messages"):
        st.divider()
        st.subheader("🌌 Export Transmission Log")
        col1, col2 = st.columns(2)

        with col1:
            chat_text = ""
            for msg in st.session_state.messages:
                role = "You" if msg["role"] == "user" else "Ruby"
                chat_text += f"{role}:\n{msg['content']}\n\n"
            st.download_button(
                label="📥 Export as TXT",
                data=chat_text,
                file_name="ruby_transmission.txt",
                mime="text/plain",
                use_container_width=True
            )

        with col2:
            chat_md = "# Ruby Transmission Log\n\n"
            for msg in st.session_state.messages:
                role = "**You**" if msg["role"] == "user" else "**Ruby**"
                chat_md += f"{role}:\n{msg['content']}\n\n---\n\n"
            st.download_button(
                label="📥 Export as Markdown",
                data=chat_md,
                file_name="ruby_transmission.md",
                mime="text/markdown",
                use_container_width=True
            )

if __name__ == "__main__":
    main()
